#include <bits/stdc++.h>
using namespace std;

int n,r,a[1003],len;

int main(){
    scanf("%d%d",&n,&r);
    if(!n){
        printf("0=0(base%d)",r);
    }else{
        int tmp=n;
        r=-r;
        while(n){
            a[++len]=(n%r+r)%r;
            if(n>=0)
                n=-(n/r);
            else
                n=-(n/r)+(n%r!=0);
        }
        printf("%d=",tmp);
        for(int i=len;i;i--)
            printf("%c",(a[i]<10?a[i]+'0':a[i]-10+'A'));
        printf("(base-%d)",r);
    }
    return 0;
}
